+export function QuickNav() {
+  const [activeId, setActiveId] = useState("");
+  const [visible, setVisible] = useState(false);
+
+  useEffect(() => {
+    const handleScroll = () => {
+      setVisible(window.scrollY > 600);
+    };
+
+    const observer = new IntersectionObserver(
