+                  type="button"
+                  onClick={() => handleClick(item.id)}
+                  title={`${item.number}. ${item.label}`}
+                  className="group relative flex items-center gap-2 px-2.5 py-1.5 rounded-lg transition-all duration-300 w-full text-left"
