+                  />
+
+                  {/* Label */}
+                  <span
+                    className="relative z-10 text-[0.6rem] font-bold tracking-wide transition-colors duration-300 whitespace-nowrap"
+                    style={{
+                      color: isActive
+                        ? "#FF5500"
+                        : "rgba(255,255,255,0.25)",
+                    }}
+                  >
+                    {item.label}
+                  </span>
+                </button>
+              );
+            })}
+          </div>
+        </motion.nav>
+      )}
+    </AnimatePresence>
+  );
+}

